import akka.actor.{ActorSystem, Props}
import scala.io.StdIn
import akka.pattern.ask
import akka.util.Timeout
import scala.concurrent.duration._
import scala.concurrent.ExecutionContext.Implicits.global

object AkkaJavaSerializationApp extends App {
  // Create an Akka system with the configuration defined in application.conf
  // This will enable Java serialization as per the config.
  val system = ActorSystem("JavaSerializationSystem")

  val myActor = system.actorOf(MyActor.props, "myActor")

  implicit val timeout: Timeout = 5.seconds

  println("Sending a test message using Akka's internal JavaSerializer...")
  val testMessage = UntrustedMessage(1, "Hello from the test sender!")

  // Akka handles the serialization and deserialization internally based on the configuration.
  // The message is implicitly serialized before being sent across actor boundaries (e.g., remote or cluster)
  // and deserialized upon receipt.
